module master_slave_d_latch (
    input wire D,
    input wire EN,
    output reg Q,
    output reg Q_not
);
    reg obf_master_Q;

    always @(posedge EN) begin
        obf_master_Q <= D;
    end

    always @(negedge EN) begin
        Q <= obf_master_Q;
        Q_not <= ~obf_master_Q;
    end
endmodule
